noncompliant:
struct S {
  int *x;
  int &y;
  S(int i, int j) :
    x(&i),  // Noncompliant, initializing x to the stack address of i
    y(j)  // Noncompliant, y is bound to variable j which has a shorter lifetime
  {}
};

compliant:
struct S {
  int *x;
  int &y;
  S(int *i, int &j) : x(i), y(j) {}
};
